void AnalyzeDll(string path)
{
    try
    {
        var asm = Assembly.LoadFrom(path);
        Console.WriteLine($"Assembly: {asm.GetName().Name} v{asm.GetName().Version}");

        var types = asm.GetTypes()
            .Where(t => t.IsPublic && !t.FullName!.StartsWith("<"))
            .OrderBy(t => t.Name)
            .ToList();

        Console.WriteLine($"Total public types: {types.Count}\n");

        // Find attributes
        var attrs = types.Where(t => t.IsClass && t.Name.Contains("Attribute")).ToList();
        if (attrs.Any())
        {
            Console.WriteLine("--- ATTRIBUTES ---");
            foreach (var attr in attrs)
            {
                Console.WriteLine($"  {attr.FullName}");
            }
            Console.WriteLine();
        }

        // Find extension methods (static classes with static methods)
        var extMethods = types.Where(t => t.IsClass && t.IsSealed && !t.IsGenericTypeDefinition)
            .Where(t => t.GetMethods(BindingFlags.Static | BindingFlags.Public)
                .Any(m => m.GetCustomAttributes()
                    .Any(a => a.GetType().Name == "ExtensionAttribute")))
            .ToList();

        if (extMethods.Any())
        {
            Console.WriteLine("--- EXTENSION METHOD CLASSES ---");
            foreach (var ext in extMethods)
            {
                Console.WriteLine($"\n  {ext.FullName}");
                var methods = ext.GetMethods(BindingFlags.Static | BindingFlags.Public)
                    .Where(m => m.GetCustomAttributes()
                        .Any(a => a.GetType().Name == "ExtensionAttribute"))
                    .OrderBy(m => m.Name)
                    .ToList();

                foreach (var method in methods)
                {
                    var paramStr = string.Join(", ", method.GetParameters()
                        .Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"    - {method.ReturnType.Name} {method.Name}({paramStr})");
                }
            }
            Console.WriteLine();
        }

        // Find builder/server related interfaces
        var serverTypes = types.Where(t => t.Name.Contains("Builder") || t.Name.Contains("Server") || 
                                          t.Name.Contains("Transport") || t.Name.Contains("Tool"))
            .OrderBy(t => t.Name)
            .ToList();

        if (serverTypes.Any())
        {
            Console.WriteLine("--- KEY TYPES (Builder/Server/Transport/Tool) ---");
            foreach (var t in serverTypes)
            {
                Console.WriteLine($"\n  {t.Name} ({(t.IsInterface ? "interface" : t.IsClass ? "class" : "struct")})");

                if (t.IsInterface)
                {
                    var methods = t.GetMethods();
                    foreach (var m in methods.Take(5))
                    {
                        Console.WriteLine($"    - {m.ReturnType.Name} {m.Name}()");
                    }
                    if (methods.Length > 5)
                        Console.WriteLine($"    ... and {methods.Length - 5} more methods");
                }
            }
            Console.WriteLine();
        }

        // Find all interfaces
        var interfaces = types.Where(t => t.IsInterface).OrderBy(t => t.Name).ToList();
        Console.WriteLine($"\n--- ALL PUBLIC INTERFACES ({interfaces.Count}) ---");
        foreach (var iface in interfaces)
        {
            Console.WriteLine($"  {iface.FullName}");
        }

    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}
