void AnalyzeAssembly(System.Reflection.Assembly asm, string name)
{
    Console.WriteLine($"\n{name}:");
    Console.WriteLine(new string('=', 50));

    var types = asm.GetTypes()
        .Where(t => t.IsPublic && !t.Name.StartsWith("<"))
        .ToList();

    Console.WriteLine($"Total public types: {types.Count}\n");

    // Attributes
    var attrs = types.Where(t => t.IsClass && t.Name.EndsWith("Attribute")).ToList();
    if (attrs.Any())
    {
        Console.WriteLine("ATTRIBUTES:");
        foreach (var a in attrs.OrderBy(a => a.Name))
            Console.WriteLine($"  - {a.FullName}");
        Console.WriteLine();
    }

    // Static classes
    var statics = types.Where(t => t.IsClass && t.IsSealed && !t.IsNested &&
                                   t.GetMethods(BindingFlags.Static | BindingFlags.Public).Length > 0)
        .OrderBy(t => t.Name).ToList();

    if (statics.Any())
    {
        Console.WriteLine($"EXTENSION METHODS (static classes): {statics.Count}");
        foreach (var s in statics)
        {
            Console.WriteLine($"\n  {s.Name}:");
            foreach (var m in s.GetMethods(BindingFlags.Static | BindingFlags.Public).OrderBy(m => m.Name))
            {
                var parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({parms})");
            }
        }
        Console.WriteLine();
    }

    // Key types
    var keyTypes = types.Where(t => t.Name.Contains("Server") || t.Name.Contains("Builder") || 
                                   t.Name.Contains("Transport") || t.Name.Contains("Tool") ||
                                   t.Name.Contains("Handler") || t.Name.Contains("Provider") ||
                                   t.Name.Contains("Request") || t.Name.Contains("Resource"))
        .OrderBy(t => t.Name).ToList();

    if (keyTypes.Any())
    {
        Console.WriteLine($"KEY TYPES: {keyTypes.Count}");
        foreach (var t in keyTypes)
        {
            var kind = t.IsInterface ? "I" : "C";
            Console.WriteLine($"  [{kind}] {t.FullName}");

            // Show methods for interfaces
            if (t.IsInterface)
            {
                var methods = t.GetMethods();
