var hosting = Assembly.LoadFrom($"{home}/.nuget/packages/modelcontextprotocol/1.0.0/lib/net10.0/ModelContextProtocol.dll");

Console.WriteLine("=== CORE PUBLIC TYPES ===");
foreach (var t in core.GetExportedTypes().OrderBy(t => t.FullName))
    Console.WriteLine($"  {t.FullName}");

Console.WriteLine("\n=== HOSTING PUBLIC TYPES ===");
foreach (var t in hosting.GetExportedTypes().OrderBy(t => t.FullName))
    Console.WriteLine($"  {t.FullName}");

// Look for attributes specifically
Console.WriteLine("\n=== ATTRIBUTES (from both) ===");
foreach (var t in core.GetExportedTypes().Concat(hosting.GetExportedTypes())
    .Where(t => t.IsSubclassOf(typeof(Attribute)))
    .OrderBy(t => t.FullName))
{
    Console.WriteLine($"  {t.FullName}");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"    .{p.Name}: {p.PropertyType.Name}");
}

// Look for extension methods
Console.WriteLine("\n=== EXTENSION METHODS (from hosting) ===");
foreach (var t in hosting.GetExportedTypes().Where(t => t.IsAbstract && t.IsSealed))
{
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.IsDefined(typeof(System.Runtime.CompilerServices.ExtensionAttribute))))
    {
        var paramType = m.GetParameters().FirstOrDefault()?.ParameterType.Name ?? "?";
