using System;
using System.Reflection;
using System.Linq;

var mainDll = "/home/runner/.nuget/packages/modelcontextprotocol/1.0.0/lib/net10.0/ModelContextProtocol.dll";
var asm = Assembly.LoadFrom(mainDll);

Console.WriteLine("=== DEPENDENCY INJECTION & DI EXTENSIONS ===\n");

// Find the IMcpServerBuilder
var builderInterface = asm.GetTypes().FirstOrDefault(t => t.Name == "IMcpServerBuilder");
if (builderInterface != null)
{
    Console.WriteLine("IMcpServerBuilder Interface:");
    Console.WriteLine($"  Namespace: Microsoft.Extensions.DependencyInjection");
    Console.WriteLine($"  Property: IServiceCollection Services");
}

Console.WriteLine("\n" + new string('=', 70) + "\n");

// Check AddMcpServer signature more carefully
var svcExtType = asm.GetTypes().FirstOrDefault(t => t.Name == "McpServerServiceCollectionExtensions");
if (svcExtType != null)
{
    Console.WriteLine("Service Collection Extensions:\n");
    var methods = svcExtType.GetMethods(BindingFlags.Static | BindingFlags.Public);
    foreach (var m in methods)
    {
        var genericArgs = m.GetGenericArguments();
        var genericPart = genericArgs.Length > 0 ? "<" + string.Join(", ", genericArgs.Select(g => g.Name)) + ">" : "";

        var parms = string.Join(", ", m.GetParameters().Select(p => 
        {
            var typeName = p.ParameterType.Name;
            if (p.ParameterType.IsGenericType)
            {
                var args = string.Join(", ", p.ParameterType.GetGenericArguments().Select(a => a.Name));
                typeName = p.ParameterType.GetGenericTypeDefinition().Name + "<" + args + ">";
            }
            return typeName + " " + p.Name;
        }));
        Console.WriteLine($"  → {m.ReturnType.Name} {m.Name}{genericPart}({parms})");
    }
}

Console.WriteLine("\n" + new string('=', 70) + "\n");

// Show how WithTools works with type discovery
Console.WriteLine("TOOL DISCOVERY & REGISTRATION PATTERN:\n");
Console.WriteLine("WithTools Overloads:");

var extType = asm.GetTypes().FirstOrDefault(t => t.Name == "McpServerBuilderExtensions");
if (extType != null)
{
    var withToolsMethods = extType.GetMethods(BindingFlags.Static | BindingFlags.Public)
        .Where(m => m.Name == "WithTools")
        .OrderBy(m => m.GetParameters().Length)
        .ToList();

    foreach (var m in withToolsMethods)
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => 
        {
            var typeName = p.ParameterType.Name;
            if (p.ParameterType.IsGenericType)
            {
                var args = string.Join(", ", p.ParameterType.GetGenericArguments().Select(a => a.Name));
                typeName = p.ParameterType.GetGenericTypeDefinition().Name + "<" + args + ">";
            }
            return typeName + " " + p.Name;
        }));
        Console.WriteLine($"\n  WithTools({parms})");
    }
}

Console.WriteLine("\n\nHow tools with constructor dependencies are discovered:");
Console.WriteLine("  1. WithTools(Assembly assembly) scans assembly for types marked with");
Console.WriteLine("     @McpServerToolTypeAttribute");
Console.WriteLine("  2. Each marked class can have public methods marked with");
Console.WriteLine("     @McpServerToolAttribute");
Console.WriteLine("  3. Tool instances are created via DI container (IServiceProvider)");
Console.WriteLine("     using constructor injection");
console.WriteLine("  4. Tool methods are exposed as MCP tools");
